use std::sync::Arc;
use uv::rtio::{self, EventLoop};
use uv::Loop;

/// Creates a new libuv event loop and returns it boxed as a trait object.
pub fn new_event_loop() -> Box<dyn EventLoop + Send> {
    // `Loop::new()` returns a `Result<Loop, uv::Error>`.
    // We unwrap safely with a clear panic message; in production code,
    // consider propagating the error instead.
    let ev_loop = Loop::new().expect("Failed to create libuv event loop");
    Box::new(ev_loop)
}

/// Trait that abstracts a libuv handle, providing access to the underlying
/// handle and its associated event loop.
pub trait UvHandle {
    /// The concrete libuv handle type.
    type Handle;

    /// Returns a reference to the underlying libuv handle.
    fn uv_handle(&self) -> &Self::Handle;

    /// Returns a reference to the event loop that owns this handle.
    fn event_loop(&self) -> &dyn EventLoop;
}

// Example implementation for a generic handle wrapper.
pub struct HandleWrapper<H> {
    handle: H,
    loop_ref: Arc<dyn EventLoop + Send + Sync>,
}

impl<H> HandleWrapper<H> {
    pub fn new(handle: H, loop_ref: Arc<dyn EventLoop + Send + Sync>) -> Self {
        Self { handle, loop_ref }
    }
}

impl<H> UvHandle for HandleWrapper<H> {
    type Handle = H;

    fn uv_handle(&self) -> &Self::Handle {
        &self.handle
    }

    fn event_loop(&self) -> &dyn EventLoop {
        self.loop_ref.as_ref()
    }
}
