#pragma once
#include <cstddef>
#include <stdexcept>
#include <utility>
#include <limits>
#include <memory>

template <typename T>
class DynamicArray {
public:
    // Constructors / Destructor
    DynamicArray() noexcept
        : data_(nullptr), size_(0), capacity_(0) {}

    DynamicArray(const DynamicArray& other)
        : data_(nullptr), size_(0), capacity_(0) {
        if (other.size_ > 0) {
            allocate_and_copy(other.size_, other.data_);
        }
    }

    DynamicArray(DynamicArray&& other) noexcept
        : data_(other.data_), size_(other.size_), capacity_(other.capacity_) {
        other.data_ = nullptr;
        other.size_ = other.capacity_ = 0;
    }

    ~DynamicArray() noexcept { deallocate(); }

    // Assignment operators
    DynamicArray& operator=(const DynamicArray& other) {
        if (this != &other) {
            DynamicArray tmp(other);
            swap(tmp);
        }
        return *this;
    }

    DynamicArray& operator=(DynamicArray&& other) noexcept {
        if (this != &other) {
            deallocate();
            data_ = other.data_;
            size_ = other.size_;
            capacity_ = other.capacity_;
            other.data_ = nullptr;
            other.size_ = other.capacity_ = 0;
        }
        return *this;
    }

    // Element access
    T& operator[](std::size_t index) noexcept { return data_[index]; }
    const T& operator[](std::size_t index) const noexcept { return data_[index]; }

    T& at(std::size_t index) {
        if (index >= size_) throw std::out_of_range("DynamicArray::at: index out of range");
        return data_[index];
    }
    const T& at(std::size_t index) const {
        if (index >= size_) throw std::out_of_range("DynamicArray::at: index out of range");
        return data_[index];
    }

    // Capacity
    std::size_t size() const noexcept { return size_; }
    std::size_t capacity() const noexcept { return capacity_; }
    bool empty() const noexcept { return size_ == 0; }

    // Modifiers
    void push_back(const T& value) {
        ensure_capacity(size_ + 1);
        new (data_ + size_) T(value);
        ++size_;
    }

    void push_back(T&& value) {
        ensure_capacity(size_ + 1);
        new (data_ + size_) T(std::move(value));
        ++size_;
    }

    void pop_back() {
        if (size_ == 0) throw std::underflow_error("DynamicArray::pop_back: empty array");
        data_[size_ - 1].~T();
        --size_;
    }

    void clear() noexcept {
        for (std::size_t i = 0; i < size_; ++i) {
            data_[i].~T();
        }
        size_ = 0;
    }

private:
    T* data_;
    std::size_t size_;
    std::size_t capacity_;

    void deallocate() noexcept {
        if (data_) {
            clear();
            operator delete[](static_cast<void*>(data_));
            data_ = nullptr;
            capacity_ = 0;
        }
    }

    void swap(DynamicArray& other) noexcept {
        std::swap(data_, other.data_);
        std::swap(size_, other.size_);
        std::swap(capacity_, other.capacity_);
    }

    void allocate_and_copy(std::size_t n, const T* src) {
        T* new_data = static_cast<T*>(operator new[](n * sizeof(T)));
        std::size_t i = 0;
        try {
            for (; i < n; ++i) {
                new (new_data + i) T(src[i]);
            }
        } catch (...) {
            for (std::size_t j = 0; j < i; ++j) {
                new_data[j].~T();
            }
            operator delete[](static_cast<void*>(new_data));
            throw;
        }
        data_ = new_data;
        size_ = capacity_ = n;
    }

    void ensure_capacity(std::size_t min_needed) {
        if (min_needed <= capacity_) return;

        std::size_t new_cap = capacity_ ? capacity_ * 2 : 1;
        const std::size_t max = std::numeric_limits<std::size_t>::max() / sizeof(T);
        if (new_cap > max) new_cap = max;
        if (new_cap < min_needed) new_cap = min_needed;

        T* new_data = static_cast<T*>(operator new[](new_cap * sizeof(T)));
        std::size_t i = 0;
        try {
            for (; i < size_; ++i) {
                new (new_data + i) T(std::move_if_noexcept(data_[i]));
            }
        } catch (...) {
            for (std::size_t j = 0; j < i; ++j) {
                new_data[j].~T();
            }
            operator delete[](static_cast<void*>(new_data));
            throw;
        }

        // Destroy old elements and free old storage
        for (std::size_t j = 0; j < size_; ++j) {
            data_[j].~T();
        }
        operator delete[](static_cast<void*>(data_));

        data_ = new_data;
        capacity_ = new_cap;
    }
};
