using UnityEngine;
using System;
using System.Threading;

public static class GameObjectFactory
{
    private static int _instanceCount = 0;
    public static int InstanceCount => _instanceCount;

    public static GameObject CreateRandomInstance(
        GameObject prefab,
        Vector3 positionMin,
        Vector3 positionMax,
        Material[] materialOptions)
    {
        if (prefab == null) throw new ArgumentNullException(nameof(prefab));
        if (materialOptions == null || materialOptions.Length == 0)
            throw new ArgumentException("Material options must not be null or empty.", nameof(materialOptions));

        // Random position within the specified bounds
        Vector3 randomPosition = new Vector3(
            UnityEngine.Random.Range(positionMin.x, positionMax.x),
            UnityEngine.Random.Range(positionMin.y, positionMax.y),
            UnityEngine.Random.Range(positionMin.z, positionMax.z));

        // Random rotation
        Quaternion randomRotation = Quaternion.Euler(
            UnityEngine.Random.Range(0f, 360f),
            UnityEngine.Random.Range(0f, 360f),
            UnityEngine.Random.Range(0f, 360f));

        // Instantiate the GameObject
        GameObject instance = UnityEngine.Object.Instantiate(prefab, randomPosition, randomRotation);

        // Assign a random material from the provided array
        Renderer renderer = instance.GetComponent<Renderer>();
        if (renderer != null)
        {
            int materialIndex = UnityEngine.Random.Range(0, materialOptions.Length);
            renderer.material = materialOptions[materialIndex];
        }

        // Thread‑safe increment of the instance counter
        Interlocked.Increment(ref _instanceCount);

        return instance;
    }
}

