#include <SDL.h>
#include <stdlib.h>
#include <stdio.h>
#include <limits.h>

/* Securely initialize an SDL surface with zeroed pixels.
 * Returns a pointer to the created surface, or NULL on failure.
 * The caller is responsible for freeing the surface with SDL_FreeSurface().
 */
SDL_Surface *init_surface(int width, int height)
{
    /* Validate dimensions */
    if (width <= 0 || height <= 0) {
        SDL_SetError("Invalid surface dimensions");
        return NULL;
    }

    const int bytes_per_pixel = 4;               /* 32‑bit RGBA */
    const Uint32 rmask = 0x00FF0000;
    const Uint32 gmask = 0x0000FF00;
    const Uint32 bmask = 0x000000FF;
    const Uint32 amask = 0xFF000000;

    /* Prevent integer overflow in pitch calculation */
    size_t pitch;
    if (__builtin_mul_overflow((size_t)width, (size_t)bytes_per_pixel, &pitch)) {
        SDL_SetError("Surface size overflow");
        return NULL;
    }

    /* Allocate zero‑initialized pixel buffer */
    void *pixels = calloc((size_t)height, pitch);
    if (!pixels) {
        SDL_SetError("Failed to allocate pixel buffer");
        return NULL;
    }

    /* Create the surface using the external pixel buffer */
    SDL_Surface *surface = SDL_CreateRGBSurfaceFrom(
        pixels,
        width,
        height,
        bytes_per_pixel * 8,   /* depth in bits */
        (int)pitch,
        rmask, gmask, bmask, amask);

    if (!surface) {
        /* SDL_CreateRGBSurfaceFrom failed – free the pixel buffer */
        free(pixels);
        /* SDL_CreateRGBSurfaceFrom already set an SDL error */
        return NULL;
    }

