public static class RandomFloatUtility
{
    public static float GetRandomFloatBetween(float[] bounds)
    {
        if (bounds == null)
            throw new ArgumentNullException(nameof(bounds));

        if (bounds.Length != 2)
            throw new ArgumentException("Array must contain exactly two elements.", nameof(bounds));

        float min = bounds[0];
        float max = bounds[1];

        if (float.IsNaN(min) || float.IsNaN(max) || float.IsInfinity(min) || float.IsInfinity(max))
            throw new ArgumentException("Bounds must be finite numbers.", nameof(bounds));

        // Ensure min <= max; swap if necessary
        if (min > max)
        {
            float temp = min;
            min = max;
            max = temp;
        }

        // UnityEngine.Random.Range for floats is inclusive on both ends
        return UnityEngine.Random.Range(min, max);
    }
}
