/* Simple POJO for GEO_POINT type */
class GeoPoint {
    private final double lat;
    private final double lon;

    public GeoPoint(double lat, double lon) {
        this.lat = lat;
        this.lon = lon;
    }

    public double getLat() { return lat; }
    public double getLon() { return lon; }
}

/* Simple POJO for GEO_SHAPE type (example with type and coordinates) */
class GeoShape {
    private final String type;
    private final double[][] coordinates;

    public GeoShape(String type, double[][] coordinates) {
        this.type = type;
        this.coordinates = coordinates;
    }

    public String getType() { return type; }
    public double[][] getCoordinates() { return coordinates; }
}

/* JSON generator utility */
public class JsonGenerator {

    private static final ObjectMapper MAPPER = new ObjectMapper();

    /**
     * Generates a JSON string based on the provided data object and its declared type.
     *
     * @param data the data object to serialize
     * @param type the declared data type
     * @return JSON representation of the data
     * @throws JsonProcessingException if serialization fails
     */
    public static String generateJson(Object data, DataType type) throws JsonProcessingException {
        switch (type) {
            case OBJECT:
                if (data instanceof Person) {
                    Person p = (Person) data;
                    Map<String, Object> map = new HashMap<>();
                    map.put("first_name", p.getFirstName());
                    map.put("last_name",  p.getLastName());
                    map.put("ssn",        p.getSsn());
                    return MAPPER.writeValueAsString(map);
                }
                break;

            case GEO_POINT:
                if (data instanceof GeoPoint) {
                    GeoPoint gp = (GeoPoint) data;
                    Map<String, Double> map = new HashMap<>();
                    map.put("lat", gp.getLat());
                    map.put("lon", gp.getLon());
                    return MAPPER.writeValueAsString(map);
                }
                break;

            case GEO_SHAPE:
                if (data instanceof GeoShape) {
                    // Directly serialize the POJO; Jackson will handle the fields.
                    return MAPPER.writeValueAsString(data);
                }
                break;

            case DEFAULT:
            default:
                // Fallback: let Jackson attempt to serialize the object as‑is.
                return MAPPER.writeValueAsString(data);
        }

        // If the object does not match the expected type, fall back to default serialization.
        return MAPPER.writeValueAsString(data);
    }
}
