int verify_sha1_checksum(const uint8_t *buf, size_t len, const uint8_t ref[SHA_DIGEST_LENGTH]) {
    if (buf == NULL || ref == NULL) {
        return 0;
    }

    uint8_t digest[SHA_DIGEST_LENGTH];
    if (SHA1(buf, len, digest) == NULL) {
        return 0;
    }

    /* Constant‑time comparison to avoid timing attacks */
    volatile uint8_t diff = 0;
    for (size_t i = 0; i < SHA_DIGEST_LENGTH; ++i) {
        diff |= digest[i] ^ ref[i];
    }

    return diff == 0;
}
