#include <lua.h>
#include <lauxlib.h>
#include <bson.h>

/* Creates a BSON document from the Lua stack.
 * Expected stack (from bottom to top):
 *   1. switch value (integer)
 *   2. regex pattern (string)   <-- used only for case 11
 *   3. regex options (string)   <-- used only for case 11
 * Returns a newly allocated bson* on success; on error the function raises a Lua error.
 */
static bson *lua_create_bson_from_stack(lua_State *L)
{
    /* Verify we have at least three arguments */
    if (lua_gettop(L) < 3) {
        luaL_error(L, "Expected at least three arguments: switch, pattern, options");
        return NULL; /* unreachable */
    }

    /* Validate switch argument */
    if (!lua_isinteger(L, 1)) {
        luaL_error(L, "Switch argument must be an integer");
        return NULL;
    }
    int switch_val = (int)lua_tointeger(L, 1);

    /* Create a new BSON document */
    bson *doc = bson_new();
    if (!doc) {
        luaL_error(L, "Failed to allocate BSON document");
        return NULL;
    }

    const char *field_name = "bsontype";

    switch (switch_val) {
        case 10: {
            if (!bson_append_null(doc, field_name, -1)) {
                bson_destroy(doc);
                luaL_error(L, "Failed to append null value to BSON");
                return NULL;
            }
            break;
        }
        case 11: {
            /* Validate pattern and options arguments */
            if (!lua_isstring(L, 2) || !lua_isstring(L, 3)) {
                bson_destroy(doc);
                luaL_error(L, "Pattern and options must be strings for regex case");
                return NULL;
            }
            const char *pattern = lua_tostring(L, 2);
            const char *options = lua_tostring(L, 3);

            if (!bson_append_regex(doc, field_name, -1, pattern, options)) {
                bson_destroy(doc);
                luaL_error(L, "Failed to append regex value to BSON");
                return NULL;
            }
            break;
        }
        default: {
            bson_destroy(doc);
            luaL_error(L, "Unsupported switch value: %d", switch_val);
            return NULL;
        }
    }

    /* Finalize the BSON document */
    if (!bson_finish(doc)) {
        bson_destroy(doc);
        luaL_error(L, "Failed to finalize BSON document");
        return NULL;
    }

    return doc;
}
