using System.Linq;
using System.Xml.Linq;

public static class XmlConfigHelper
{
    /// <summary>
    /// Replaces a configuration node identified by a key attribute.
    /// The existing node(s) with the specified key are removed and a new node
    /// with the same key is added under the document root.
    /// </summary>
    /// <param name="filePath">Full path to the XML configuration file.</param>
    /// <param name="key">The value of the key attribute identifying the node.</param>
    /// <param name="newNodeContent">The content of the new configuration node (excluding the key attribute).</param>
    public static void ReplaceConfigurationNode(string filePath, string key, XElement newNodeContent)
    {
        if (string.IsNullOrWhiteSpace(filePath))
            throw new ArgumentException("File path must be provided.", nameof(filePath));

        if (string.IsNullOrWhiteSpace(key))
            throw new ArgumentException("Key must be provided.", nameof(key));

        if (newNodeContent == null)
            throw new ArgumentNullException(nameof(newNodeContent));

        if (!File.Exists(filePath))
            throw new FileNotFoundException("XML configuration file not found.", filePath);

        // Load the XML document securely (XDocument does not process external DTDs, mitigating XXE).
        XDocument doc = XDocument.Load(filePath, LoadOptions.PreserveWhitespace);

        // Remove any existing nodes with the matching key attribute.
        var nodesToRemove = doc.Descendants()
                               .Where(e => (string)e.Attribute("key") == key)
                               .ToList();

        foreach (var node in nodesToRemove)
        {
            node.Remove();
        }

        // Prepare the new node, ensuring it carries the same key attribute.
        XElement nodeToAdd = new XElement(newNodeContent);
        nodeToAdd.SetAttributeValue("key", key);

        // Append the new node to the document's root element.
        doc.Root?.Add(nodeToAdd);

        // Save the updated document back to the file.
        doc.Save(filePath);
    }
}
