function decodeWBXML(wbxmlStr) {
  // Convert a base64 or raw binary string to Uint8Array safely
  const toUint8Array = (str) => {
    const isBase64 = /^[A-Za-z0-9+/=]+$/.test(str);
    let binary;
    if (isBase64) {
      try {
        binary = atob(str);
      } catch {
        throw new Error('Invalid base64 WBXML string');
      }
    } else {
      binary = str;
    }
    const len = binary.length;
    const arr = new Uint8Array(len);
    for (let i = 0; i < len; i++) {
      arr[i] = binary.charCodeAt(i) & 0xff;
    }
    return arr;
  };

  const data = toUint8Array(wbxmlStr);
  let offset = 0;

  const readByte = () => {
    if (offset >= data.length) throw new Error('Unexpected end of WBXML data');
    return data[offset++];
  };

  const readMultiByteInt = () => {
    let result = 0;
    let byte;
    do {
      byte = readByte();
      result = (result << 7) | (byte & 0x7f);
    } while (byte & 0x80);
    return result;
  };

  // ----- WBXML Header -----
  const version = readByte();               // WBXML version (e.g., 0x03)
  const publicId = readMultiByteInt();      // Public identifier (0 = unknown)
  const charset = readMultiByteInt();       // Charset (e.g., 106 = UTF-8)
  const stringTableLength = readMultiByteInt();

  // Skip string table (not needed for ActiveSync codepages)
  offset += stringTableLength;

  // ----- Simple ActiveSync codepage map (extend as needed) -----
  const codepages = [
    { // Codepage 0
      0x05: 'Sync',
      0x06: 'Responses',
      0x07: 'Add',
      0x08: 'Change',
      0x09: 'Delete',
      0x0A: 'Fetch',
      0x0B: 'SyncKey',
      0x0C: 'ClientId',
      0x0D: 'ServerId',
      0x0E: 'Status',
      // ... add remaining tag tokens for codepage 0
    },
    // Additional codepages can be added here
  ];
  let currentCodepage = 0;

  const decodeString = () => {
    const start = offset;
    while (offset < data.length && data[offset] !== 0) offset++;
    if (offset >= data.length) throw new Error('Unterminated string');
    const str = new TextDecoder('utf-8').decode(data.subarray(start, offset));
    offset++; // skip null terminator
    return str;
  };

  const parseElement = () => {
    const token = readByte();

    // SWITCH_PAGE – change active codepage
    if (token === 0x00) {
      currentCodepage = readByte();
      return parseElement();
    }

    // END – close current element
    if (token === 0x01) {
      return null;
    }

    // STR_I – inline string
    if (token === 0x03) {
      return decodeString();
    }

    // OPAQUE – raw binary data
    if (token === 0xC3) {
      const length = readMultiByteInt();
      const opaque = data.subarray(offset, offset + length);
      offset += length;
      return opaque; // Uint8Array
    }

    // Literal tag (0x04–0x7F) – map token to tag name
    if (token >= 0x04 && token <= 0x7F) {
      const tagName = codepages[currentCodepage][token] || `UNKNOWN_${token}`;
      const element = { tag: tagName, attrs: {}, children: [] };

      // NOTE: ActiveSync WBXML does not use attributes; they are ignored safely.

      // Parse children until END token
      while (true) {
        const next = data[offset];
        if (next === 0x01) { // END
          offset++; // consume END
          break;
        }
        const child = parseElement();
        if (child === null) break;
        element.children.push(child);
      }
      return element;
    }

    // Unsupported token – fail fast to avoid undefined behavior
    throw new Error(`Unsupported WBXML token: 0x${token.toString(16)}`);
  };

  // Parse the document body
  const result = [];
  while (offset < data.length) {
    const element = parseElement();
    if (element !== null) result.push(element);
  }

  // Return a single object if the document has one root element
  return result.length === 1 ? result[0] : result;
}
