/* Safely multiply two size_t values, detecting overflow. */
static int safe_mul_size_t(size_t a, size_t b, size_t *out) {
    if (a == 0 || b == 0) {
        *out = 0;
        return 0;
    }
    if (a > SIZE_MAX / b) {
        return -1; /* overflow */
    }
    *out = a * b;
    return 0;
}

/*
 * Extend an array of pointers to `new_len` elements.
 * Returns the reallocated array on success, or NULL on failure.
 * The original array is left unchanged if reallocation fails.
 * New slots are zero‑initialized.
 */
void **extend_pointer_array(void **array, size_t current_len, size_t new_len) {
    if (new_len <= current_len) {
        return array; /* No extension needed */
    }

    size_t new_bytes;
    if (safe_mul_size_t(new_len, sizeof(void *), &new_bytes) != 0) {
        return NULL; /* Size overflow */
    }

    void **new_array = realloc(array, new_bytes);
    if (!new_array) {
        return NULL; /* Allocation failure */
    }

    /* Zero‑initialize the newly added elements */
    memset(new_array + current_len, 0,
           (new_len - current_len) * sizeof(void *));

    return new_array;
}
