typedef struct {
    uint32_t bank_width;      /* Width of a flash bank in bytes */
    uint32_t sector_count;    /* Number of flash sectors */
    uintptr_t base_addr;      /* Base address of the flash region */
    uintptr_t end_addr;       /* End address (exclusive) of the flash region */
} Device;

/* Safely parse a range string of the form "0xSTART-0xEND". */
static int parse_range(const char *range, uintptr_t *out_start, uintptr_t *out_end) {
    if (!range || !out_start || !out_end) {
        return -1;
    }

    const char *dash = strchr(range, '-');
    if (!dash) {
        return -1;
    }

    /* Extract start and end substrings without overrunning buffers. */
    char start_str[32] = {0};
    char end_str[32]   = {0};

    size_t start_len = dash - range;
    size_t end_len   = strlen(dash + 1);

    if (start_len >= sizeof(start_str) || end_len >= sizeof(end_str)) {
        return -1;
    }

    memcpy(start_str, range, start_len);
    memcpy(end_str, dash + 1, end_len);

    errno = 0;
    unsigned long start = strtoul(start_str, NULL, 0);
    if (errno != 0) {
        return -1;
    }

    errno = 0;
    unsigned long end = strtoul(end_str, NULL, 0);
    if (errno != 0) {
        return -1;
    }

    if (end < start) {
        return -1;
    }

    *out_start = (uintptr_t)start;
    *out_end   = (uintptr_t)end;
    return 0;
}

/* Print flash information and expose key values via environment variables. */
void print_flash_info(const Device *dev, const char *range) {
    if (!dev) {
        fprintf(stderr, "Error: device pointer is NULL.\n");
        return;
    }

    /* Optional user‑supplied address range. */
    if (range) {
        uintptr_t r_start = 0, r_end = 0;
        if (parse_range(range, &r_start, &r_end) == 0) {
            printf("User range: 0x%zx - 0x%zx\n", (size_t)r_start, (size_t)r_end);
        } else {
            fprintf(stderr, "Warning: invalid range string \"%s\" ignored.\n", range);
        }
    }

    printf("Flash Bank Width : %u bytes\n", dev->bank_width);
    printf("Sector Count     : %u\n", dev->sector_count);
    printf("Base Address     : 0x%zx\n", (size_t)dev->base_addr);
    printf("End Address      : 0x%zx\n", (size_t)dev->end_addr);

    /* Safely construct environment variable values. */
    char buf[64];

    if (snprintf(buf, sizeof(buf), "0x%zx", (size_t)dev->base_addr) < (int)sizeof(buf)) {
        setenv("FLASH_BASE", buf, 1);
    }

    if (snprintf(buf, sizeof(buf), "%u", dev->sector_count) < (int)sizeof(buf)) {
        setenv("FLASH_SECTOR_COUNT", buf, 1);
    }

    if (snprintf(buf, sizeof(buf), "0x%zx", (size_t)dev->end_addr) < (int)sizeof(buf)) {
        setenv("FLASH_END", buf, 1);
    }
}
