```c
#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <errno.h>
#include <limits.h>

#define MAX_LABEL_LEN 64
#define INITIAL_CAPACITY 4

typedef struct Edge {
    int dest;               // Index of destination vertex
    struct Edge *next;      // Next edge in adjacency list
} Edge;

typedef struct Vertex {
    char label[MAX_LABEL_LEN];
    Edge *adj;              // Head of adjacency list
} Vertex;

typedef struct Graph {
    Vertex *vertices;
    size_t vertex_count;
    size_t capacity;
} Graph;

/* ---------- Utility Functions ---------- */
static void safe_free(void *ptr) {
    if (ptr) free(ptr);
}

/* Read a line from stdin safely */
static int read_line(char *buf, size_t size) {
    if (fgets(buf, (int)size, stdin) == NULL) {
        return -1;
    }
    size_t len = strlen(buf);
    if (len && buf[len - 1] == '\n')
        buf[len - 1] = '\0';
    return 0;
}

/* Convert string to int with error checking */
static int parse_int(const char *str, int *out) {
    char *endptr = NULL;
    errno = 0;
    long val = strtol(str, &endptr, 10);
    if (errno != 0 || endptr == str || *endptr != '\0' ||
        val < INT_MIN || val > INT_MAX) {
        return -1;
    }
    *out = (int)val;
    return 0;
}

/* ---------- Graph Management ---------- */
static int graph_init(Graph *g) {
    g->vertices = calloc(INITIAL_CAPACITY, sizeof(Vertex));
    if (!g->vertices) return -1;
    g->vertex_count = 0;
    g->capacity = INITIAL_CAPACITY;
    return 0;
}

static void graph_free(Graph *g) {
    if (!g) return;
    for (size_t i = 0; i < g->vertex_count; ++i) {
        Edge *e = g->vertices[i].adj;
        while (e) {
            Edge *tmp = e;
            e = e->next;
            safe_free(tmp);
        }
    }
    safe_free(g->vertices);
}

/* Ensure capacity for a new vertex */
static int graph_ensure_capacity(Graph *g) {
    if (g->vertex_count < g->capacity) return 0;
    size_t new_cap = g->capacity * 2;
    Vertex *new_buf = realloc(g->vertices, new_cap * sizeof(Vertex));
    if (!new_buf) return -1;
    memset(new_buf + g->capacity, 0, (new_cap - g->capacity) * sizeof(Vertex));
    g->vertices = new_buf;
    g->capacity = new_cap;
    return 0;
}

/* Add a vertex with a label */
static int graph_add_vertex(Graph *g, const char *label) {
    if (graph_ensure_capacity(g) != 0) return -1;
    Vertex *v = &g->vertices[g->vertex_count];
    strncpy(v->label, label, MAX_LABEL_LEN - 1);
    v->label[MAX_LABEL_LEN - 1] = '\0';
    v->adj = NULL;
    g->vertex_count++;
    return 0;
}

/* Add a directed edge from src to dest */
static int graph_add_edge(Graph *g, int src, int dest) {
    if (src < 0 || (size_t)src >= g->vertex_count ||
        dest < 0 || (size_t)dest >= g->vertex_count) {
        return -1;
    }
    Edge *e = malloc(sizeof(Edge));
    if (!e) return -1;
    e->dest = dest;
    e->next = g->vertices[src].adj;
    g->vertices[src].adj = e;
    return 0;
}

/* Display the graph */
static void graph_display(const Graph *g) {
    printf("\n--- Graph ---\n");
    for (size_t i = 0; i < g->vertex_count; ++i) {
        printf("Vertex %zu: %s\n", i, g->vertices[i].label);
        printf("  Edges to: ");
        Edge *e = g->vertices[i].adj;
        if (!e) {
            printf("none");
        } else {
            while (e) {
                printf("%d ", e->dest);
                e = e->next;
            }
        }
        printf("\n");
    }
}

/* Modify a vertex label */
static int graph_modify_vertex(Graph *g, int idx, const char *new_label) {
    if (idx < 0 || (size_t)idx >= g->vertex_count) return -1;
    strncpy(g->vertices[idx].label, new_label, MAX_LABEL_LEN - 1);
    g->vertices[idx].label[MAX_LABEL_LEN - 1] = '\0';
    return 0;
}

/* Insert a new vertex and connect it to existing vertices */
static int graph_insert_vertex_with_edges(Graph *g, const char *label,
                                          const int *targets, size_t target_cnt) {
    if (graph_add_vertex(g, label) != 0) return -1;
    int new_idx = (int)(g->vertex_count - 1);
    for (size_t i = 0; i < target_cnt; ++i) {
        if (graph_add_edge(g, new_idx, targets[i]) != 0) {
            /* rollback partial edges */
            Edge *e = g->vertices[new_idx].adj;
            while (e) {
                Edge *tmp = e;
                e = e->next;
                safe_free(tmp);
            }
            g->vertices[new_idx].adj = NULL;
            return -1;
        }
    }
    return 0;
}

/* ---------- Interactive Function ---------- */
void interactive_graph_demo(void) {
    Graph g;
    if (graph_init(&g) != 0) {
        fprintf(stderr, "Failed to initialize graph.\n");
        return;
    }

    /* Initial static graph */
    graph_add_vertex(&g, "A");
    graph_add_vertex(&g, "B");
    graph_add_vertex(&g, "C");
    graph_add_edge(&g, 0, 1); /* A -> B */
    graph_add_edge(&g, 1, 2); /* B -> C */
    graph_add_edge(&g, 2, 0); /* C -> A */

    graph_display(&g);

    /* --- Modify a vertex --- */
    char line[128];
    int idx;
    printf("\nEnter vertex index to modify: ");
    if (read_line(line, sizeof(line)) != 0 ||
        parse_int(line, &idx) != 0 ||
        idx < 0 || (size_t)idx >= g.vertex_count) {
        fprintf(stderr, "Invalid vertex index.\n");
        graph_free(&g);
        return;
    }

    printf("Enter new label (max %d chars): ", MAX_LABEL_LEN - 1);
    if (read_line(line, sizeof(line)) != 0) {
        fprintf(stderr, "Failed to read label.\n");
        graph_free(&g);
        return;
    }
    if (graph_modify_vertex(&g, idx, line) != 0) {
        fprintf(stderr, "Failed to modify vertex.\n");
        graph_free(&g);
        return;
    }

    graph_display(&g);

    /* --- Insert a new vertex with edges --- */
    printf("\nEnter label for new vertex: ");
    if (read_line(line, sizeof(line)) != 0) {
        fprintf(stderr, "Failed to read label.\n");
        graph_free(&g);
        return;
    }
    char new_label[MAX_LABEL_LEN];
    strncpy(new_label, line, MAX_LABEL_LEN - 1);
    new_label[MAX_LABEL_LEN - 1] = '\0';

    printf("Enter number of outgoing edges from new vertex: ");
    if (read_line(line, sizeof(line)) != 0 ||
        parse_int(line, &idx) != 0 || idx < 0) {
        fprintf(stderr, "Invalid number.\n");
        graph_free(&g);
        return;
    }
    int edge_cnt = idx;
    int *targets = NULL;
    if (edge_cnt > 0) {
        targets = calloc((size_t)edge_cnt, sizeof(int));
        if (!targets) {
            fprintf(stderr, "Memory allocation failed.\n");
            graph_free(&g);
            return;
        }
        for (int i = 0; i < edge_cnt; ++i) {
            printf("Enter destination vertex index for edge %d: ", i + 1);
            if (read_line(line, sizeof(line)) != 0 ||
                parse_int(line, &idx) != 0 ||
                idx < 0 || (size_t)idx >= g.vertex_count) {
                fprintf(stderr, "Invalid vertex index.\n");
                safe_free(targets);
                graph_free(&g);
                return;
            }
            targets[i] = idx;
        }
    }

    if (graph_insert_vertex_with_edges(&g, new_label,
                                       targets, (size_t)edge_cnt) != 0) {
        fprintf(stderr, "Failed to insert new vertex.\n");
        safe_free(targets);
        graph_free(&g);
        return;
    }
    safe_free(targets);

    graph_display(&g);
    graph_free(&g);
