/**
 * Render a template with a list of themes after checking if the client IP is blocked.
 *
 * @param \Psr\Http\Message\ServerRequestInterface $request  The incoming request.
 * @param \Psr\Http\Message\ResponseInterface      $response The response to write to.
 * @param \PDO                                      $pdo      PDO instance for DB access.
 *
 * @return void
 */
function renderThemeTemplate(\Psr\Http\Message\ServerRequestInterface $request,
                             \Psr\Http\Message\ResponseInterface $response,
                             \PDO $pdo): void
{
    // -------------------------------------------------------------------------
    // 1. Retrieve client IP address safely
    // -------------------------------------------------------------------------
    $serverParams = $request->getServerParams();
    $clientIp = $serverParams['REMOTE_ADDR'] ?? '';

    // -------------------------------------------------------------------------
    // 2. Check if IP is blocked using a prepared statement (prevents SQLi)
    // -------------------------------------------------------------------------
    $stmt = $pdo->prepare('SELECT 1 FROM blocked_ips WHERE ip = :ip LIMIT 1');
    $stmt->execute([':ip' => $clientIp]);

    if ($stmt->fetchColumn()) {
        // IP is blocked – display a safe, escaped message
        $message = 'Your IP address is blocked.';
        $response->getBody()->write(
            htmlspecialchars($message, ENT_QUOTES | ENT_SUBSTITUTE, 'UTF-8')
        );
        return;
    }

    // -------------------------------------------------------------------------
    // 3. Retrieve a sanitized list of theme files from the themes directory
    // -------------------------------------------------------------------------
    $themeDir = __DIR__ . '/themes';
    $themes   = [];

    if (is_dir($themeDir)) {
        foreach (scandir($themeDir) as $file) {
            // Accept only files with a safe name pattern and .php extension
            if (preg_match('/^[a-zA-Z0-9_-]+\.php$/', $file) &&
                is_file($themeDir . '/' . $file)) {
                $themes[] = $file;
            }
        }
    }

    // -------------------------------------------------------------------------
    // 4. Render the template safely (output buffering + variable isolation)
    // -------------------------------------------------------------------------
    $templatePath = __DIR__ . '/templates/theme_list.php';

    if (is_file($templatePath)) {
        // Isolate variables to avoid leaking scope
        $data = ['themes' => $themes];

        // Extract variables in a controlled manner
        extract($data, EXTR_SKIP);

        // Capture template output
        ob_start();
        include $templatePath;
        $rendered = ob_get_clean();

        // Write rendered content to the response
        $response->getBody()->write($rendered);
    } else {
        // Fallback message if template is missing
        $response->getBody()->write('Template not found.');
    }
}
