std::pair<long long, bool> selectSubset(const std::vector<int>& values, long long target) {
    if (values.empty()) {
        return {0, target == 0};
    }

    std::random_device rd;
    std::mt19937 gen(rd());

    const int maxIterations = 1000;
    long long bestSum = 0;
    bool exact = false;
    std::size_t bestCount = std::numeric_limits<std::size_t>::max();

    std::vector<std::size_t> indices(values.size());
    std::iota(indices.begin(), indices.end(), 0);

    for (int iter = 0; iter < maxIterations; ++iter) {
        std::shuffle(indices.begin(), indices.end(), gen);

        long long currentSum = 0;
        std::size_t currentCount = 0;

        for (std::size_t idx : indices) {
            long long prospective = currentSum + static_cast<long long>(values[idx]);
            if (prospective > target) {
                continue;
            }
            currentSum = prospective;
            ++currentCount;
            if (currentSum == target) {
                break;
            }
        }

        long long bestDiff = std::llabs(target - bestSum);
        long long currentDiff = std::llabs(target - currentSum);

        if (currentDiff < bestDiff ||
            (currentDiff == bestDiff && currentCount < bestCount)) {
            bestSum = currentSum;
            bestCount = currentCount;
            exact = (currentSum == target);
            if (exact) {
                break;
            }
        }
    }

    return {bestSum, exact};
}
