import java.util.*;

public class DisjointPairCounter {

    // Union-Find (Disjoint Set Union) implementation
    private static class UnionFind {
        private final int[] parent;
        private final int[] rank;

        UnionFind(int size) {
            parent = new int[size];
            rank = new int[size];
            for (int i = 0; i < size; i++) {
                parent[i] = i;
                rank[i] = 0;
            }
        }

        int find(int x) {
            if (parent[x] != x) {
                parent[x] = find(parent[x]); // Path compression
            }
            return parent[x];
        }

        void union(int x, int y) {
            int rootX = find(x);
            int rootY = find(y);
            if (rootX == rootY) return;

            // Union by rank
            if (rank[rootX] < rank[rootY]) {
                parent[rootX] = rootY;
            } else if (rank[rootX] > rank[rootY]) {
                parent[rootY] = rootX;
            } else {
                parent[rootY] = rootX;
                rank[rootX]++;
            }
        }
    }

    /**
     * Counts the number of disjoint pairs in the given array.
     * A pair (i, j) is considered disjoint if the elements at indices i and j belong to different sets.
     *
     * @param arr input array with unique integers
     * @return number of disjoint pairs
     */
    public static long countDisjointPairs(int[] arr) {
        if (arr == null) {
            throw new IllegalArgumentException("Input array must not be null.");
        }

        int n = arr.length;
        UnionFind uf = new UnionFind(n);

        // Example union logic (optional):
        // If you have a specific condition to union elements, apply it here.
        // For demonstration, we leave all elements in separate sets.

        long disjointCount = 0L;

        for (int i = 0; i < n; i++) {
            for (int j = i + 1; j < n; j++) {
                long startNs = System.nanoTime();

                boolean isDisjoint = uf.find(i) != uf.find(j);
                if (isDisjoint) {
                    disjointCount++;
                }

                long elapsedMs = (System.nanoTime() - startNs) / 1_000_000;
                System.out.println("Pair (" + i + ", " + j + ") check took " + elapsedMs + " ms");
            }
        }

        return disjointCount;
    }

    // Example usage
    public static void main(String[] args) {
        int[] sample = {1, 2, 3, 4, 5};
        long result = countDisjointPairs(sample);
        System.out.println("Total disjoint pairs: " + result);
    }
