static unsigned int toUnsigned(int value) noexcept {
    if (value < 0) return 0u;
    return static_cast<unsigned int>(value);
}

// Convert signed long to unsigned long safely (saturate negatives to 0)
static unsigned long toUnsigned(long value) noexcept {
    if (value < 0) return 0ul;
    return static_cast<unsigned long>(value);
}

// Convert double to unsigned long safely (saturate negatives to 0, clamp to max)
static unsigned long toUnsigned(double value) noexcept {
    if (std::isnan(value) || value <= 0.0) return 0ul;
    if (value >= static_cast<double>(std::numeric_limits<unsigned long>::max()))
        return std::numeric_limits<unsigned long>::max();
    return static_cast<unsigned long>(value);
}

// Process an array of ints
std::vector<unsigned int> processArray(const std::vector<int>& input) noexcept {
    std::vector<unsigned int> result;
    result.reserve(input.size());
    for (std::size_t i = 0; i < input.size(); ++i) {
        result.push_back(toUnsigned(input[i]));
